    {
      "input": {
        "channel": "meta",
        "steps": [
          {
            "meta": {
              "name": "custom-meta",
              "content": "value",
              "attribute": "test"
            }
          },
          {
            "remove_meta": "custom-meta"
          }
        ]
      },
      "expected_output": "<title>It's Over 9000!</title><meta name=\"description\" content=\"For those who helped create the Genki Dama\">"
