    {
      "input": {
        "channel": "opengraph",
        "steps": [
          {
            "url": "https://www.domain.com"
          }
        ]
      },
      "expected_output": "<meta property=\"og:title\" content=\"Over 9000 Thousand!\" /><meta property=\"og:description\" content=\"For those who helped create the Genki Dama\" /><meta property=\"og:url\" content=\"https://www.domain.com\" />"
    }
  ]
}

