Here are the public test cases for feature4_1_core_fields:
{
  "description": "JSON-LD structured-data document. The renderer emits a single application/ld+json script element wrapping a JSON object that always starts with the schema.org context and a type, then a name (from title) and description. Callers may override the title, description, or type; defaults supply name and description when not overridden. Note slashes inside URLs/the context are escaped in the JSON output, and the description text is embedded literally (no HTML escaping at this layer).",
  "cases": [
    {
      "input": {
        "channel": "jsonld",
        "steps": [
          {
            "title": "Kamehamehaaaaaaaa"
          }
        ]
      },
      "expected_output": "<script type=\"application/ld+json\">{\"@context\":\"https:\\/\\/schema.org\",\"@type\":\"WebPage\",\"name\":\"Kamehamehaaaaaaaa\",\"description\":\"For those who helped create the Genki Dama\"}</script>"
    },
    {
      "input": {
        "channel": "jsonld",
        "steps": [
          {
            "description": "Kamehamehaaaaaaaa"
          }
        ]
      },
      "expected_output": "<script type=\"application/ld+json\">{\"@context\":\"https:\\/\\/schema.org\",\"@type\":\"WebPage\",\"name\":\"Over 9000 Thousand!\",\"description\":\"Kamehamehaaaaaaaa\"}</script>"
    },
    {
      "input": {
        "channel": "jsonld",
        "steps": [
          {
            "type": "sayajin"
          }
        ]
      },
      "expected_output": "<script type=\"application/ld+json\">{\"@context\":\"https:\\/\\/schema.org\",\"@type\":\"sayajin\",\"name\":\"Over 9000 Thousand!\",\"description\":\"For those who helped create the Genki Dama\"}</script>"
    },
    {
      "input": {
        "channel": "jsonld",
        "steps": [
          {
            "description": "\"Foo bar\" -> abc"
          }
        ]
      },
      "expected_output": "<script type=\"application/ld+json\">{\"@context\":\"https:\\/\\/schema.org\",\"@type\":\"WebPage\",\"name\":\"Over 9000 Thousand!\",\"description\":\"\\\"Foo bar\\\" -> abc\"}</script>"
    }
  ]
}

